import collections

class TrieNode:
    def __init__(self):
        self.children = collections.defaultdict(TrieNode)
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            node = node.children[char]
        node.is_end_of_word = True

    def _collect_all_words_from_node(self, node: TrieNode, current_path: str, results: list):
        if node.is_end_of_word:
            results.append(current_path)
        for char, child_node in node.children.items():
            self._collect_all_words_from_node(child_node, current_path + char, results)

    def search_prefix(self, prefix: str) -> list[str]:
        node = self.root
        for char in prefix:
            if char not in node.children:
                return []
            node = node.children[char]

        results = []
        self._collect_all_words_from_node(node, prefix, results)
        return sorted(results)

class ReverseTrie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        reversed_word = word[::-1]
        node = self.root
        for char in reversed_word:
            node = node.children[char]
        node.is_end_of_word = True

    def _collect_all_reversed_words_from_node(self, node: TrieNode, current_reversed_path: str, results: list):
        if node.is_end_of_word:
            results.append(current_reversed_path)
        for char, child_node in node.children.items():
            self._collect_all_reversed_words_from_node(child_node, current_reversed_path + char, results)

    def search_suffix(self, suffix: str) -> list[str]:
        reversed_suffix = suffix[::-1]
        node = self.root
        for char in reversed_suffix:
            if char not in node.children:
                return []
            node = node.children[char]

        collected_reversed_words = []
        self._collect_all_reversed_words_from_node(node, reversed_suffix, collected_reversed_words)

        final_results = [r_word[::-1] for r_word in collected_reversed_words]
        return sorted(list(set(final_results)))

if __name__ == "__main__":
    words = ["apple", "apply", "apricot", "banana", "bandana", "cat", "dog", "elephant", "ant", "plant", "splinter"]

    print("--- Prefix Search ---")
    prefix_trie = Trie()
    for word in words:
        prefix_trie.insert(word)

    print(f"Words: {words}\n")

    test_prefixes = ["ap", "ban", "c", "d", "ele", "z", "appl", "a"]
    for prefix in test_prefixes:
        found_words = prefix_trie.search_prefix(prefix)
        print(f"Prefix '{prefix}': {found_words}")

    print("\n--- Suffix Search ---")
    suffix_trie = ReverseTrie()
    for word in words:
        suffix_trie.insert(word)

    test_suffixes = ["ple", "ana", "t", "og", "nt", "er", "z", "e"]
    for suffix in test_suffixes:
        found_words = suffix_trie.search_suffix(suffix)
        print(f"Suffix '{suffix}': {found_words}")
